  BUILD_DATE = new Date().toISOString().split('T')[0];
}

export { VERSION, BUILD_DATE };

// Helper function to get formatted version string
export function getVersionString(includeV = true): string {
  return includeV ? `v${VERSION}` : VERSION;
}

